@app.route('/analytics/documents/by-category', methods=['GET'])
def documents_by_category():
    pipeline = [
        {
            '$group': {
                '_id': '$category',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'}
            }
        },
        {
            '$sort': {'count': -1}
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'analytics': results}), 200


@app.route('/analytics/documents/by-author', methods=['GET'])
def documents_by_author():
    pipeline = [
        {
            '$group': {
                '_id': '$author_id',
                'document_count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'average_views': {'$avg': '$views'}
            }
        },
        {
            '$lookup': {
                'from': 'users',
                'let': {'author_id': {'$toObjectId': '$_id'}},
                'pipeline': [
                    {'$match': {'$expr': {'$eq': ['$_id', '$$author_id']}}}
                ],
                'as': 'author_info'
            }
        },
        {
            '$unwind': {
                'path': '$author_info',
                'preserveNullAndEmptyArrays': True
            }
        },
        {
            '$sort': {'document_count': -1}
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'analytics': results}), 200


@app.route('/analytics/documents/trending', methods=['GET'])
def trending_documents():
    days = int(request.args.get('days', 7))
    limit = int(request.args.get('limit', 10))
    
    from_date = datetime.utcnow()
    from datetime import timedelta
    from_date = from_date - timedelta(days=days)
    
    pipeline = [
        {
            '$match': {
                'created_at': {'$gte': from_date}
            }
        },
        {
            '$addFields': {
                'engagement_score': {
                    '$add': [
                        {'$multiply': ['$views', 1]},
                        {'$multiply': ['$likes', 5]}
                    ]
                }
            }
        },
        {
            '$sort': {'engagement_score': -1}
        },
        {
            '$limit': limit
        },
        {
            '$project': {
                'title': 1,
                'category': 1,
                'author_id': 1,
                'views': 1,
                'likes': 1,
                'engagement_score': 1,
                'created_at': 1
            }
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'trending_documents': results}), 200


